import React, { useEffect, useState } from "react";

const API = "http://localhost:5000/api";

export default function Logs() {
  const [logs, setLogs] = useState([]);
  const [batchId, setBatchId] = useState("");

  const [form, setForm] = useState({
    batch_id: "",
    action: "",
    description: "",
  });

  // 🔥 FETCH LOGS (based on batchId)
  const fetchLogs = async () => {
    if (!batchId) return;

    try {
      const token = localStorage.getItem("token");

      const res = await fetch(`${API}/logs/${batchId}`, {
        headers: {
          Authorization: `Bearer ${token}`,
        },
      });

      const data = await res.json();

      if (Array.isArray(data)) {
        setLogs(data);
      } else if (Array.isArray(data.logs)) {
        setLogs(data.logs);
      } else {
        setLogs([]);
      }

    } catch (err) {
      console.error("Error fetching logs:", err);
      setLogs([]);
    }
  };

  useEffect(() => {
    fetchLogs();
  }, [batchId]);

  // 🔥 CREATE LOG
  const addLog = async () => {
    if (!form.batch_id || !form.action) {
      alert("Fill required fields");
      return;
    }

    try {
      const token = localStorage.getItem("token");

      await fetch(`${API}/logs`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${token}`,
        },
        body: JSON.stringify(form),
      });

      setForm({
        batch_id: "",
        action: "",
        description: "",
      });

      fetchLogs();
    } catch (err) {
      console.error("Error adding log:", err);
    }
  };

  return (
    <div className="p-6 space-y-6">
      <h1 className="text-2xl font-bold">Logs</h1>

      {/* 🔍 SELECT BATCH */}
      <input
        placeholder="Enter Batch ID"
        value={batchId}
        onChange={(e) => setBatchId(e.target.value)}
        className="p-2 bg-white/10 rounded"
      />

      {/* ➕ CREATE LOG */}
      <div className="bg-white/10 p-4 rounded grid md:grid-cols-3 gap-3">

        <input
          placeholder="Batch ID"
          value={form.batch_id}
          onChange={(e) =>
            setForm({ ...form, batch_id: e.target.value })
          }
          className="p-2 bg-white/10 rounded"
        />

        <input
          placeholder="Action (e.g. Harvested)"
          value={form.action}
          onChange={(e) =>
            setForm({ ...form, action: e.target.value })
          }
          className="p-2 bg-white/10 rounded"
        />

        <input
          placeholder="Description"
          value={form.description}
          onChange={(e) =>
            setForm({ ...form, description: e.target.value })
          }
          className="p-2 bg-white/10 rounded"
        />

        <button
          onClick={addLog}
          className="bg-green-600 text-white rounded"
        >
          Add Log
        </button>
      </div>

      {/* 📋 LOG LIST */}
      {logs.length === 0 ? (
        <p>No logs found</p>
      ) : (
        logs.map((l) => (
          <div key={l.log_id} className="bg-white/10 p-3 rounded mt-3">
            <p className="font-semibold">{l.action}</p>
            <p className="text-sm">{l.description}</p>
            <p className="text-xs text-gray-400">
              {l.created_at || "No date"}
            </p>
          </div>
        ))
      )}
    </div>
  );
}
